import{_ as n,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"85. Gender Transition Leave","description":"","frontmatter":{"title":"85. Gender Transition Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave"]},"headers":[],"relativePath":"ebas/mspp/leave/85-gender-transition-leave.md","filePath":"ebas/mspp/leave/85-gender-transition-leave.md"}'),a={name:"ebas/mspp/leave/85-gender-transition-leave.md"};function s(i,e,p,d,l,g){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_85-gender-transition-leave" tabindex="-1">85. Gender Transition Leave <a class="header-anchor" href="#_85-gender-transition-leave" aria-label="Permalink to &quot;85. Gender Transition Leave&quot;">​</a></h1><p><strong>a.</strong> The Employer encourages a culture that is supportive of transgender and gender diverse Employees and recognises the importance of providing a safe environment for Employees undertaking gender transition.</p><p><strong>b.</strong> Gender Transition refers to the process where a transgender Employee commences living as a member of another gender. This is sometimes referred to ‘affirming’ their gender. This may occur through medical, social or legal changes.</p><p><strong>c.</strong> Employees may give effect to their transition in a number of ways and are not required to be undergoing specific types of changes, such as surgery, to access leave under this clause.</p><p><strong>85.2</strong> Amount of gender transition leave</p><p><strong>a.</strong> An Employee (other than a Casual Employee) who commences living as a member of another gender is entitled Gender Transition Leave for the purpose of supporting the Employee’s transition. Gender Transition Leave will comprise:</p><p><strong>(i)</strong> up to 4 weeks (20 days) paid leave for essential and necessary gender affirmation procedures, and</p><p><strong>(ii)</strong> up to 48 weeks of unpaid leave.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>b.</strong> The Gender Transition Leave entitlements outlined in clause 85.2a are available to be taken by the Employee within the first 52 weeks after they commence living as a member of another gender.</p><p><strong>c.</strong> Essential gender affirmation procedures may include:</p><p><strong>(i)</strong> medical or psychological appointments, or</p><p><strong>(ii)</strong> hormonal appointments, or</p><p><strong>(iii)</strong> surgery and associated appointments, or</p><p><strong>(iv)</strong> appointments to alter the Employee’s legal status or amend the Employee’s gender on legal documentation, or</p><p><strong>(v)</strong> any other similar necessary appointment or procedure to give effect to the Employee’s transition as agreed with the Employer.</p><p><strong>d.</strong> An Employee who is entitled to unpaid Gender Transition Leave may, in conjunction with all or part of that leave utilise accrued Annual or Long Service Leave, provided that the combined total of all paid and unpaid leave taken does not exceed 52 continuous weeks.</p><p><strong>e.</strong> Gender Transition Leave may be taken as consecutive, single or part days as agreed with the Employer.</p><p><strong>f.</strong> Leave under this clause will not accrue from year to year and cannot be cashed out on termination of employment.</p><p><strong>85.3</strong> Gender Transition Leave – Casual employees Casual Employees are entitled to access unpaid leave of up to 52 continuous weeks duration for gender transition purposes.</p><p><strong>85.4</strong> Notice and evidence requirements</p><p><strong>a.</strong> An Employee seeking to access Gender Transition Leave must provide the Employer with at least 4 weeks’ written notice of their intended commencement date and expected period of leave, unless otherwise agreed by the Employer.</p><p><strong>b.</strong> An Employee seeking to access Gender Transition Leave may be required to provide suitable supporting documentation or evidence of their attendance at essential gender affirmation procedures. This may be in the form of a document issued by an AHPRA Registered Practitioner, a lawyer, or a State, Territory or Federal government organisation, statutory declaration or other suitable supporting documentation.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>ALLOWANCE</p><p>Plain language terms: transition leave, gender affirming leave.</p>',26)])])}const u=n(a,[["render",s]]);export{m as __pageData,u as default};
